@namespace Lumeo

@{
    var context = new DropdownMenuRadioGroupContext(_value, EventCallback.Factory.Create<string>(this, OnValueSelected));
}

<CascadingValue Value="context" IsFixed="false">
    <div role="group" @attributes="AdditionalAttributes">
        @ChildContent
