@namespace Lumeo
@implements IDisposable

@{
    var subContext = new DropdownMenuSubContext(
        _open,
        EventCallback.Factory.Create<bool>(this, SetOpen),
        _wrapperId,
        _triggerId,
        _contentId,
        EventCallback.Factory.Create(this, CloseTree),
        ScheduleClose,
        CancelClose,
        EventCallback.Factory.Create(this, OpenFromKeyboard),
        ConsumeKeyboardOpen);
}

<CascadingValue Value="subContext" IsFixed="false">
    <div id="@_wrapperId" class="relative" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [CascadingParameter] public DropdownMenu.DropdownMenuContext? RootContext { get; set; }
    [CascadingParameter] public DropdownMenuSubContext? ParentSubContext { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _open;
    private readonly string _wrapperId = LumeoIds.New("dropdown-sub");
    internal readonly string _triggerId = LumeoIds.New("dropdown-sub-trigger");
    internal readonly string _contentId = LumeoIds.New("dropdown-sub-content");

    private CancellationTokenSource? _closeCts;
    private bool _disposed;

    // Set when the submenu is opened via the keyboard (ArrowRight). The content
    // consumes it on its first open render to move focus to the first item —
    // race-free, replacing a fixed Task.Delay that guessed when the content existed.
    private bool _openByKeyboard;

    private async Task SetOpen(bool value)
    {
        if (_open == value) return;
        _open = value;
        await InvokeAsync(StateHasChanged);
    }

    // Open from the keyboard: flag it first (before the render SetOpen triggers) so
    // the content's OnAfterRender sees it and focuses the first item.
    private async Task OpenFromKeyboard()
    {
        _openByKeyboard = true;
        await SetOpen(true);
    }

    // Consume-once: the content calls this when it first renders open and focuses
    // the first item only if the open was keyboard-initiated (hover-open must not
    // steal focus).
    private bool ConsumeKeyboardOpen()
    {
        if (!_openByKeyboard) return false;
        _openByKeyboard = false;
        return true;
    }

    private async Task CloseTree()
    {
        await SetOpen(false);
        if (ParentSubContext is not null)
        {
            await ParentSubContext.CloseTree.InvokeAsync();
        }
        else if (RootContext is not null)
        {
            await RootContext.SetOpen.InvokeAsync(false);
        }
    }

    private void CancelClose()
    {
        try { _closeCts?.Cancel(); } catch (ObjectDisposedException) { }
        _closeCts?.Dispose();
        _closeCts = null;
    }

    private void ScheduleClose()
    {
        if (_disposed) return;
        CancelClose();
        _closeCts = new CancellationTokenSource();
        var token = _closeCts.Token;
        _ = Task.Run(async () =>
        {
            try
            {
                await Task.Delay(200, token);
                if (token.IsCancellationRequested || _disposed) return;
                await InvokeAsync(async () => await SetOpen(false));
            }
            // A teardown that races the delay (Dispose cancels the token) must never
            // surface an unobserved exception or fire SetOpen on a torn-down component.
            catch (TaskCanceledException) { }
            catch (ObjectDisposedException) { }
        });
    }

    public void Dispose()
    {
        _disposed = true;
        // Cancels + disposes _closeCts and nulls it, so a scheduled close cannot
        // fire SetOpen on this torn-down component (ObjectDisposedException).
        CancelClose();
    }

    public record DropdownMenuSubContext(
        bool IsOpen,
        EventCallback<bool> SetOpen,
        string WrapperId,
        string TriggerId,
        string ContentId,
        EventCallback CloseTree,
        Action ScheduleClose,
        Action CancelClose,
        EventCallback OpenByKeyboard,
        Func<bool> ConsumeKeyboardOpen);
}

@namespace Lumeo
@implements IAsyncDisposable

@if (SubContext.IsOpen)
{
    <div id="@SubContext.ContentId"
         role="menu"
         aria-orientation="vertical"
         class="@CssClass"
         tabindex="-1"
         @onkeydown="HandleKeyDown"
         @onmouseenter="HandleMouseEnter"
         @onmouseleave="HandleMouseLeave"
         @onmousedown:stopPropagation="true"
         @ontouchstart:stopPropagation="true"
         @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public DropdownMenuSub.DropdownMenuSubContext SubContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _positioned;
    private int _focusedIndex = -1;

    private string CssClass => Cx.Merge("fixed z-50 min-w-[8rem] overflow-hidden rounded-md border border-border/60 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (SubContext.IsOpen && !_positioned)
        {
            await PositionWithFlip();
            _positioned = true;
            _focusedIndex = -1;
            // Keyboard-opened (ArrowRight): move focus to the first item now that the
            // content actually exists. Hover-open does not set the flag, so it never
            // steals focus from the pointer.
            if (SubContext.ConsumeKeyboardOpen())
            {
                _focusedIndex = 0;
                try { await Interop.FocusMenuItemByIndex(SubContext.ContentId, 0); }
                catch (JSDisconnectedException) { }
            }
        }
        else if (!SubContext.IsOpen && _positioned)
        {
            await Cleanup();
        }
    }

    private async Task PositionWithFlip()
    {
        var side = "right";
        try
        {
            var triggerRect = await Interop.GetElementRect(SubContext.TriggerId);
            var viewport = await Interop.GetViewportSize();
            // Estimate content width; flip if not enough room on the right (use 200px as conservative width).
            if (triggerRect is not null && triggerRect.X + triggerRect.Width + 200 > viewport.Width)
            {
                side = "left";
            }
        }
        catch (JSDisconnectedException) { }

        await Interop.PositionFixed(SubContext.ContentId, SubContext.TriggerId, "start", false, side);
    }

    private async Task HandleMouseEnter()
    {
        SubContext.CancelClose();
        await Task.CompletedTask;
    }

    private void HandleMouseLeave()
    {
        SubContext.ScheduleClose();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await SubContext.CloseTree.InvokeAsync();
                break;
            case "ArrowLeft":
                SubContext.CancelClose();
                await SubContext.SetOpen.InvokeAsync(false);
                try { await Interop.FocusElement(SubContext.TriggerId); } catch (JSDisconnectedException) { }
                break;
            case "ArrowDown":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = (_focusedIndex + 1) % count;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "ArrowUp":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = _focusedIndex <= 0 ? count - 1 : _focusedIndex - 1;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "Home":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = 0;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "End":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = count - 1;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(SubContext.ContentId); } catch (JSDisconnectedException) { }
        _positioned = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_positioned) await Cleanup();
    }
}

@namespace Lumeo

<button id="@SubContext.TriggerId"
        type="button"
        role="menuitem"
        tabindex="-1"
        class="@CssClass"
        data-state="@(SubContext.IsOpen ? "open" : "closed")"
        aria-haspopup="menu"
        aria-expanded="@SubContext.IsOpen.ToString().ToLower()"
        aria-controls="@SubContext.ContentId"
        disabled="@Disabled"
        @onclick="HandleClick"
        @onmouseenter="HandleMouseEnter"
        @onmouseleave="HandleMouseLeave"
        @onkeydown="HandleKeyDown"
        @attributes="AdditionalAttributes">
    @ChildContent
    <Blazicon Svg="Lucide.ChevronRight" class="ms-auto h-4 w-4" />
</button>

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public DropdownMenuSub.DropdownMenuSubContext SubContext { get; set; } = default!;
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Row vertical padding tracks the ambient DensityScope; Comfortable
    // reproduces the historical `py-1.5`. The mobile touch floor stays.
    private string PadYClass => Density switch
    {
        Lumeo.Density.Compact => "py-1",
        Lumeo.Density.Spacious => "py-2.5",
        _ => "py-1.5"
    };

    private string CssClass => Cx.Merge("relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2", PadYClass, "min-h-11 sm:min-h-0 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground data-[state=open]:bg-accent data-[state=open]:text-accent-foreground disabled:pointer-events-none disabled:opacity-50 disabled:cursor-not-allowed", Class);

    private async Task HandleClick()
    {
        if (Disabled) return;
        SubContext.CancelClose();
        await SubContext.SetOpen.InvokeAsync(!SubContext.IsOpen);
    }

    private async Task HandleMouseEnter()
    {
        if (Disabled) return;
        SubContext.CancelClose();
        if (!SubContext.IsOpen)
        {
            await SubContext.SetOpen.InvokeAsync(true);
        }
    }

    private void HandleMouseLeave()
    {
        if (!SubContext.IsOpen) return;
        SubContext.ScheduleClose();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        // Enter and Space are deliberately NOT handled here: this is a native
        // <button>, so the browser synthesizes a click for them and HandleClick
        // performs the toggle. Opening from keydown as well made keyboard
        // activation a net no-op (keydown opened, the synthesized click
        // immediately toggled the submenu closed again).
        switch (e.Key)
        {
            case "ArrowRight":
                SubContext.CancelClose();
                if (SubContext.IsOpen)
                {
                    // Already open (e.g. via hover): the content exists, focus its
                    // first item immediately — no render to wait for.
                    try { await Interop.FocusMenuItemByIndex(SubContext.ContentId, 0); }
                    catch (JSDisconnectedException) { }
                }
                else
                {
                    // Open from the keyboard and let the content focus its first item
                    // when it actually renders (race-free; replaces a fixed Task.Delay
                    // that guessed when the content would exist).
                    await SubContext.OpenByKeyboard.InvokeAsync();
                }
                break;
        }
    }
}

@namespace Lumeo

@* The `group` class + `data-state` attribute let consumers rotate a chevron on open with
   `group-data-[state=open]:rotate-180` on any descendant icon — no EventCallbacks or bindings needed. *@
@if (AsChild)
{
    @* asChild: no wrapper — the slot carries `group` + data-state + the trigger id, so a
       Lumeo <Button> child becomes the single trigger and a chevron inside it still rotates
       via group-data-[state=open]. The top-level menu positions against the DropdownMenu
       root wrapper (not the trigger), so forwarding the id is just for focus/sub-menu use. *@
    <CascadingValue Value="Slot" IsFixed="false">
        @if (ChildContentSlot is not null)
        {
            @ChildContentSlot(Slot)
        }
        else
        {
            @ChildContent
        }
    </CascadingValue>
}
else
{
    <div id="@_triggerId"
         class="@CssClass"
         role="button"
         data-state="@(Context.IsOpen ? "open" : "closed")"
         aria-haspopup="menu"
         aria-expanded="@Context.IsOpen.ToString().ToLower()"
         aria-disabled="@(Disabled ? "true" : null)"
         aria-controls="@Context.ContentId"
         @onclick="Toggle"
         @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@code {
    [CascadingParameter] public DropdownMenu.DropdownMenuContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Tier-2 escape hatch for <see cref="AsChild"/> with arbitrary markup —
    /// receives the <see cref="TriggerSlot"/> to splat manually. Lumeo
    /// <c>&lt;Button&gt;</c> children need only <see cref="AsChild"/>.</summary>
    [Parameter] public RenderFragment<TriggerSlot>? ChildContentSlot { get; set; }

    /// <summary>
    /// When <c>true</c>, renders NO wrapper and cascades a <see cref="TriggerSlot"/>
    /// (carrying <c>group</c> + <c>data-state</c> so a descendant chevron still rotates,
    /// plus the trigger id and menu ARIA) that a cooperating child folds onto its own
    /// single root element — the Radix <c>asChild</c> goal. Prefer a <c>&lt;button&gt;</c>
    /// child. Default <c>false</c> keeps the current <c>role=button</c> wrapper.
    /// </summary>
    [Parameter] public bool AsChild { get; set; }

    /// <summary>
    /// When true the trigger ignores clicks and is marked <c>aria-disabled</c>.
    /// The live <c>@onclick</c> sits on this outer <c>role="button"</c> element,
    /// not the wrapped <see cref="Button"/>, so disabling only the inner button
    /// (as <see cref="DropdownButton"/>/<see cref="SplitButton"/> do) previously
    /// still let a click on the trigger padding open the menu — this gates that.
    /// </summary>
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    internal string TriggerId => _triggerId;
    private readonly string _triggerId = LumeoIds.New("dropdown-trigger");

    private string CssClass => Cx.Merge("group inline-flex", Cx.When(Disabled, "pointer-events-none opacity-50"), Class);

    private TriggerSlot Slot => new(
        Id: _triggerId,
        Class: CssClass,
        Attributes: BuildAttrs(),
        OnClick: EventCallback.Factory.Create<MouseEventArgs>(this, _ => Toggle()));

    private IReadOnlyDictionary<string, object> BuildAttrs()
    {
        var d = new Dictionary<string, object>
        {
            ["data-state"] = Context.IsOpen ? "open" : "closed",
            ["aria-haspopup"] = "menu",
            ["aria-expanded"] = Context.IsOpen ? "true" : "false",
            ["aria-controls"] = Context.ContentId,
        };
        if (Disabled) d["aria-disabled"] = "true";
        if (AdditionalAttributes is not null)
            foreach (var kv in AdditionalAttributes) d[kv.Key] = kv.Value; // author wins on collision
        return d;
    }

    private async Task Toggle()
    {
        if (Disabled) return;
        await Context.SetOpen.InvokeAsync(!Context.IsOpen);
    }
}
